for _ in range(q):
    parts=input().split()
    op,i=parts[0],int(parts[1])
    if op=='P':
        print(-1 if i==0 else (i-1)//3)
    elif op=='C':
        ch=[j for j in [3*i+1,3*i+2,3*i+3] if j<n]
        print(*ch if ch else ['none'])
    elif op=='M':
        ch=[j for j in [3*i+1,3*i+2,3*i+3] if j<n]
        print(-1 if not ch else min(ch,key=lambda j:a[j]))

